import React, { useState } from "react";
import { FaTooth, FaTeethOpen, FaTeeth, FaMinus, FaPlus, FaRegDotCircle, FaRegSquare, FaRegSmile, FaRegTimesCircle, FaRegGrinStars } from "react-icons/fa"; // Use outros ícones se quiser

// Configuração dos dentes (pode expandir para decíduos se quiser)
const DENTES_SUP = [18,17,16,15,14,13,12,11,21,22,23,24,25,26,27,28];
const DENTES_INF = [48,47,46,45,44,43,42,41,31,32,33,34,35,36,37,38];
// Faces do quadrado anatômico
const FACES = ["vestibular", "mesial", "coroa", "distal", "palatina"];
// Ícones de tratamentos
const ICONES = [
  { key: "normal", icon: <FaTooth />, label: "Normal" },
  { key: "implante", icon: <FaRegDotCircle />, label: "Implante" },
  { key: "coroa", icon: <FaRegGrinStars />, label: "Coroa" },
  { key: "extracao", icon: <FaRegTimesCircle />, label: "Extração" },
  // adicione mais conforme sua necessidade!
];

export default function OdontogramaDigital() {
  // Estado das faces selecionadas por dente, ex: {"11": {vestibular: true, ...}, ...}
  const [facesSelecionadas, setFacesSelecionadas] = useState({});
  // Estado dos dentes selecionados por checkbox
  const [dentesSelecionados, setDentesSelecionados] = useState({});
  // Tipo de tratamento selecionado (por dente)
  const [tipoDente, setTipoDente] = useState({});

  // Seleção de face individual
  function toggleFace(dente, face) {
    setFacesSelecionadas(fs => ({
      ...fs,
      [dente]: {
        ...fs[dente],
        [face]: !fs[dente]?.[face]
      }
    }));
  }

  // Checkbox azul: seleciona/desseleciona o dente inteiro (todas faces)
  function toggleDenteCheckbox(dente) {
    const all = FACES.reduce((acc, face) => ({...acc, [face]: true}), {});
    setDentesSelecionados(ds => ({
      ...ds,
      [dente]: !ds[dente]
    }));
    setFacesSelecionadas(fs => ({
      ...fs,
      [dente]: !dentesSelecionados[dente] ? all : FACES.reduce((acc, f) => ({...acc, [f]: false}), {})
    }));
  }

  // Clique no ícone de tratamento para o dente selecionado
  function handleIconeClick(dente, key) {
    setTipoDente(td => ({
      ...td,
      [dente]: td[dente] === key ? null : key
    }));
  }

  // Renderiza todos os dentes (superior/inferior)
  function renderDentes(arr, arcada) {
    return arr.map(num => (
      <div key={num} className="flex flex-col items-center mx-1">
        {/* Checkbox azul */}
        <input
          type="checkbox"
          checked={!!dentesSelecionados[num]}
          onChange={() => toggleDenteCheckbox(num)}
          className="accent-blue-600 mb-1"
          style={{width: 18, height: 18}}
        />
        {/* Quadrado anatômico (SVG) */}
        <OdontoQuadrado
          dente={num}
          faces={facesSelecionadas[num] || {}}
          onClickFace={face => toggleFace(num, face)}
          tipo={tipoDente[num] || "normal"}
        />
        {/* Números FDI */}
        <span className="text-xs mt-1">{num}</span>
      </div>
    ));
  }

  // Renderiza ícones de tratamento para dente selecionado
  function renderIcones(dente) {
    return (
      <div className="flex gap-2 mt-2 justify-center">
        {ICONES.map(ic => (
          <button
            key={ic.key}
            title={ic.label}
            onClick={() => handleIconeClick(dente, ic.key)}
            className={`p-2 border rounded ${tipoDente[dente] === ic.key ? 'bg-blue-100' : 'bg-white'} hover:bg-blue-50`}
            style={{ fontSize: 20 }}
            type="button"
          >
            {ic.icon}
          </button>
        ))}
      </div>
    );
  }

  // Dente ativo (selecionado para ícone)
  const denteAtivo = Object.keys(dentesSelecionados).find(d => dentesSelecionados[d]);

  return (
    <div className="w-full max-w-6xl mx-auto p-4 bg-white rounded-xl shadow">
      {/* Título */}
      <div className="text-lg font-bold text-center mb-4">Odontograma</div>

      {/* Dentes superiores */}
      <div className="flex justify-center mb-2">{renderDentes(DENTES_SUP, "sup")}</div>
      {/* Dentes inferiores */}
      <div className="flex justify-center mt-2">{renderDentes(DENTES_INF, "inf")}</div>

      {/* Legenda faces */}
      <div className="flex gap-6 mt-6 justify-center text-sm">
        <div>
          <span className="inline-block w-4 h-4 mr-1 align-middle rounded bg-orange-400 border border-gray-400" /> Selecionado
        </div>
        <div>
          <span className="inline-block w-4 h-4 mr-1 align-middle rounded bg-gray-300 border border-gray-400" /> Não selecionado
        </div>
      </div>

      {/* Ícones tratamento */}
      {denteAtivo && (
        <div className="mt-8">
          <div className="text-center font-semibold mb-1">Tipo de tratamento dente {denteAtivo}</div>
          {renderIcones(denteAtivo)}
        </div>
      )}
    </div>
  );
}

// SVG quadrado anatômico para cada dente, faces destacáveis
function OdontoQuadrado({ faces, onClickFace, tipo }) {
  // Cores padrão; pode evoluir para status individual
  function cor(face) {
    return faces[face] ? "#fbbf24" : "#f3f4f6"; // laranja ou cinza claro
  }
  function border(face) {
    return faces[face] ? "#ea580c" : "#999";
  }

  // Ícone extra (ex: implante)
  let iconeTipo = null;
  if (tipo === "implante") iconeTipo = <FaRegDotCircle className="absolute text-blue-500 left-1/2 -translate-x-1/2 top-1/2 -translate-y-1/2" style={{fontSize: 26}} />;
  if (tipo === "coroa") iconeTipo = <FaRegGrinStars className="absolute text-yellow-500 left-1/2 -translate-x-1/2 top-1/2 -translate-y-1/2" style={{fontSize: 26}} />;
  if (tipo === "extracao") iconeTipo = <FaRegTimesCircle className="absolute text-red-500 left-1/2 -translate-x-1/2 top-1/2 -translate-y-1/2" style={{fontSize: 26}} />;
  // ... outros tipos

  return (
    <div className="relative" style={{width: 36, height: 36}}>
      <svg viewBox="0 0 36 36" width={36} height={36}>
        {/* Mesial */}
        <polygon
          points="3,3 12,3 12,33 3,33"
          fill={cor("mesial")}
          stroke={border("mesial")}
          strokeWidth={1.2}
          onClick={() => onClickFace("mesial")}
          style={{cursor: "pointer"}}
        />
        {/* Distal */}
        <polygon
          points="24,3 33,3 33,33 24,33"
          fill={cor("distal")}
          stroke={border("distal")}
          strokeWidth={1.2}
          onClick={() => onClickFace("distal")}
          style={{cursor: "pointer"}}
        />
        {/* Vestibular */}
        <polygon
          points="12,3 24,3 24,12 12,12"
          fill={cor("vestibular")}
          stroke={border("vestibular")}
          strokeWidth={1.2}
          onClick={() => onClickFace("vestibular")}
          style={{cursor: "pointer"}}
        />
        {/* Palatina/Lingual */}
        <polygon
          points="12,24 24,24 24,33 12,33"
          fill={cor("palatina")}
          stroke={border("palatina")}
          strokeWidth={1.2}
          onClick={() => onClickFace("palatina")}
          style={{cursor: "pointer"}}
        />
        {/* Coroa/Oclusal */}
        <polygon
          points="12,12 24,12 24,24 12,24"
          fill={cor("coroa")}
          stroke={border("coroa")}
          strokeWidth={1.2}
          onClick={() => onClickFace("coroa")}
          style={{cursor: "pointer"}}
        />
        {/* Contorno quadrado */}
        <rect x="3" y="3" width="30" height="30" fill="none" stroke="#bbb" strokeWidth={1.3} rx={6} ry={6} />
      </svg>
      {iconeTipo}
    </div>
  );
}
